345	func (pod *Pod) imagesNamesSet() sets.Set[containerImage] {
346		imageNamesSet := sets.New[containerImage]()
347		for _, container := range append(pod.Spec.Containers, pod.Spec.InitContainers...) {
348			imageNamesSet.Insert(containerImage{
349				imageName: fmt.Sprintf("//%s", container.Image),
350				skipCache: container.ImagePullPolicy == corev1.PullAlways,
351			})
352		}
353		return imageNamesSet
354	}
