400	// ensureArchitectureLabels adds labels for the given requirement to the pod. Labels are added to indicate
401	// the supported architectures and index pods by architecture or by whether they support more than one architecture.
402	// In this case, single-architecture is meant as a pod that supports only one architecture: all the images in the pod
403	// may be manifest-list, but the intersection of the architectures is a single value.
404	func (pod *Pod) ensureArchitectureLabels(requirement corev1.NodeSelectorRequirement) {
405		if requirement.Values == nil {
406			return
407		}
408		switch len(requirement.Values) {
409		case 0:
410			// if the requirement has no values, we set the NoSupportedArchLabel as a label for the node. That's a dummy
411			// and non-available-by-default label that we use to prevent the pod from being scheduled when it cannot run all
412			// the containers in at least one architecture.
413			pod.EnsureLabel(utils.NoSupportedArchLabel, "")
414		case 1:
415			pod.EnsureLabel(utils.SingleArchLabel, "")
416		default:
417			pod.EnsureLabel(utils.MultiArchLabel, "")
418		}
419		validArchitectures := utils.AllSupportedArchitecturesSet()
420		for _, value := range requirement.Values {
421			if validArchitectures.Has(value) {
422				pod.EnsureLabel(utils.ArchLabelValue(value), "")
423			}
424		}
425	}
